// // This is a 3-bit wide, 2-to-1 demultiplexer. The output 'o' will be selected from either input 'x' or input 'y' based on the value of the select signal 's'. If 's' is 0, the output will be the same as input 'x'; if 's' is 1, the output will follow input 'y'.
module top_module(
    x, y, s, o
);input [2:0] x, y;
    input s;
    output [2:0] o;

    assign o = ({3{~s}} & x) | ({3{s}} & y);endmodule
